'use client';

import { useState, useEffect, useMemo } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { format, subDays, parseISO } from 'date-fns';
import { Calendar } from '@/components/Calendar';
import { Heatmap } from '@/components/Heatmap';
import { PhotoModal } from '@/components/PhotoModal';
import { supabase } from '@/lib/supabase';
import toast from 'react-hot-toast';

export default function ParentPage() {
    const router = useRouter();
    const [logs, setLogs] = useState<{ id: string; study_date: string; image_url: string | null; student_name?: string }[]>([]);
    const [loading, setLoading] = useState(true);
    const [roomName, setRoomName] = useState('');

    // 필터링 상태 추가
    const [selectedStudent, setSelectedStudent] = useState<string>('all');

    const [selectedImage, setSelectedImage] = useState<{ id: string; src: string; date: string; studentName?: string } | null>(null);

    useEffect(() => {
        const savedRoom = localStorage.getItem('premium_group_name');
        if (!savedRoom) {
            toast.error('입장 정보가 없습니다. 다시 로그인해주세요!');
            router.push('/');
            return;
        }
        setRoomName(savedRoom);

        const fetchRecords = async (room: string) => {
            const { data, error } = await supabase
                .from('study_logs')
                .select('id, study_date, image_url, student_name')
                .eq('room_name', room)
                .order('study_date', { ascending: false });

            if (error) {
                console.error('Error fetching records:', error);
                toast.error('데이터를 불러오는데 실패했어요.');
            } else if (data) {
                setLogs(data);
            }
            setLoading(false);
        };

        fetchRecords(savedRoom);
    }, [router]);

    // Derived State: 학생 목록 추출
    const students = useMemo(() => {
        const names = logs.map(l => l.student_name).filter(Boolean) as string[];
        return Array.from(new Set(names)).sort();
    }, [logs]);

    // Derived State: 선택된 학생의 로그 필터링
    const filteredLogs = useMemo(() => {
        if (selectedStudent === 'all') return logs;
        return logs.filter(log => log.student_name === selectedStudent);
    }, [logs, selectedStudent]);

    // Derived State: 스트릭 계산 (필터링된 로그 기반)
    const streak = useMemo(() => {
        if (!filteredLogs.length) return 0;

        const uniqueDates = Array.from(new Set(filteredLogs.map(d => d.study_date))).sort((a, b) => b.localeCompare(a));
        const today = new Date();
        const todayStr = format(today, 'yyyy-MM-dd');
        const yesterdayStr = format(subDays(today, 1), 'yyyy-MM-dd');

        let currentStreak = 0;
        let checkDate = today;

        const isTodayDone = uniqueDates.includes(todayStr);
        const isYesterdayDone = uniqueDates.includes(yesterdayStr);

        let startDateStr = '';

        if (isTodayDone) {
            startDateStr = todayStr;
        } else if (isYesterdayDone) {
            startDateStr = yesterdayStr;
        } else {
            return 0;
        }

        currentStreak = 1;
        checkDate = parseISO(startDateStr);

        let currentIndex = uniqueDates.indexOf(startDateStr);

        while (currentIndex !== -1 && currentIndex + 1 < uniqueDates.length) {
            const nextDateStr = uniqueDates[currentIndex + 1];
            const expectedNextDate = subDays(checkDate, 1);
            const expectedNextDateStr = format(expectedNextDate, 'yyyy-MM-dd');

            if (nextDateStr === expectedNextDateStr) {
                currentStreak++;
                checkDate = expectedNextDate;
                currentIndex++;
            } else {
                break;
            }
        }

        return currentStreak;
    }, [filteredLogs]);

    const handleDateClick = (date: string) => {
        // 날짜 클릭 시 해당 날짜의 첫 번째 (또는 가장 최신) 사진 모달 표시
        const log = filteredLogs.find(l => l.study_date === date);
        if (log?.image_url) {
            setSelectedImage({ id: log.id, src: log.image_url, date, studentName: log.student_name });
        }
    };

    if (loading) return null;

    const markedDates = Array.from(new Set(filteredLogs.map(l => l.study_date)));

    const getStreakMessage = (current: number) => {
        if (current === 0) return '오늘부터 바로 시작해볼까요? 🚀';
        if (current === 1) return '시작이 반이에요! 화이팅! 💪';
        if (current === 2) return '이틀 연속! 훌륭해요! ✨';
        if (current === 3) return '작심삼일 극복! 대단해요! 🎉';
        if (current < 7) return '꾸준함의 힘을 믿어요! 👍';
        if (current < 30) return '완벽한 습관이 되었네요! 🔥';
        return '전설적인 꾸준함입니다! 👑';
    };

    return (
        <main className="flex min-h-screen flex-col items-center p-6 bg-gray-50">
            <div className="w-full max-w-md space-y-6">
                <div className="flex items-center justify-between pt-4">
                    <Link href="/" className="text-gray-500 hover:text-gray-900 font-medium">
                        &larr; 메인으로
                    </Link>
                    <h1 className="text-xl font-bold text-gray-900">학습 기록</h1>
                    <button
                        onClick={() => {
                            if (confirm('접속 정보를 초기화하고 메인으로 돌아가시겠습니까?')) {
                                localStorage.removeItem('premium_group_name');
                                localStorage.removeItem('premium_group_id');
                                localStorage.removeItem('premium_student_name');
                                router.push('/');
                            }
                        }}
                        className="text-gray-400 hover:text-red-500 text-sm font-medium transition-colors"
                    >
                        로그아웃 🔄
                    </button>
                </div>

                <div className="text-center space-y-4">
                    <div className="flex flex-col items-center gap-3">
                        <div className="inline-flex px-4 py-1.5 bg-white rounded-full shadow-sm border border-gray-100 text-sm text-gray-500">
                            🏫 방 이름: <span className="font-bold text-gray-800 ml-1">{roomName}</span>
                        </div>

                        {/* 학생 필터링 드롭다운 */}
                        <div className="relative w-full max-w-[200px] animate-in fade-in slide-in-from-top-2">
                            <select
                                value={selectedStudent}
                                onChange={(e) => setSelectedStudent(e.target.value)}
                                className="w-full appearance-none bg-white border border-gray-200 text-gray-700 py-2.5 px-4 pr-10 rounded-xl leading-tight focus:outline-none focus:ring-2 focus:ring-toss-blue focus:border-toss-blue font-medium shadow-sm cursor-pointer transition-all"
                            >
                                <option value="all">👨‍👩‍👧‍👦 전체 학생 모아보기</option>
                                {students.map(student => (
                                    <option key={student} value={student}>
                                        👤 {student} 기록만 보기
                                    </option>
                                ))}
                            </select>
                            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-gray-400">
                                <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20">
                                    <path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z" />
                                </svg>
                            </div>
                        </div>
                    </div>

                    <div className="bg-gradient-to-br from-toss-blue to-blue-600 rounded-3xl p-6 text-white shadow-xl transform transition-transform hover:scale-[1.02]">
                        <h2 className="text-lg font-medium opacity-90 mb-1">
                            {selectedStudent === 'all' ? '우리가족/학급 연속 공부일 🔥' : `${selectedStudent} 최고 연속 기록 🔥`}
                        </h2>
                        <p className="text-5xl font-extrabold tracking-tight">
                            {streak}일째
                        </p>
                        <p className="text-sm mt-3 opacity-80 font-medium">
                            {getStreakMessage(streak)}
                        </p>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                    <Heatmap
                        logs={filteredLogs.map(l => ({ date: l.study_date, hasImage: !!l.image_url }))}
                        onDateClick={handleDateClick}
                    />
                </div>

                {/* Recent Photo Section */}
                {filteredLogs.find(l => l.image_url) && (
                    <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 space-y-3">
                        <div className="flex items-center justify-between">
                            <h3 className="font-bold text-gray-900 flex items-center gap-2">
                                📸 최근 인증 사진
                            </h3>
                            <span className="text-xs text-gray-400">
                                {filteredLogs.find(l => l.image_url)?.study_date}
                                {filteredLogs.find(l => l.image_url)?.student_name ? ` (${filteredLogs.find(l => l.image_url)?.student_name})` : ''}
                            </span>
                        </div>
                        <div
                            className="relative aspect-video w-full bg-gray-50 rounded-2xl overflow-hidden cursor-pointer hover:opacity-95 transition-opacity border border-gray-50 flex items-center justify-center"
                            onClick={() => {
                                const latest = filteredLogs.find(l => l.image_url);
                                if (latest?.image_url) {
                                    setSelectedImage({ id: latest.id, src: latest.image_url, date: latest.study_date, studentName: latest.student_name });
                                }
                            }}
                        >
                            {filteredLogs.find(l => l.image_url)?.image_url === 'deleted' ? (
                                <div className="text-center p-4">
                                    <span className="text-3xl mb-1 block">💣</span>
                                    <p className="text-xs font-bold text-gray-500">자동 삭제됨</p>
                                </div>
                            ) : (
                                <img
                                    src={filteredLogs.find(l => l.image_url)?.image_url || ''}
                                    alt="공부 인증 사진"
                                    className="object-cover w-full h-full"
                                />
                            )}
                            <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent" />
                        </div>
                    </div>
                )}

                <div className="shadow-xl rounded-3xl overflow-hidden bg-white">
                    <Calendar markedDates={markedDates} logs={filteredLogs} onDateClick={handleDateClick} />
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-toss-blue font-bold">
                            {markedDates.length}
                        </div>
                        <div>
                            <p className="font-bold text-gray-900">
                                {selectedStudent === 'all' ? '이번 달 함께 공부한 날' : '이번 달 출석일'}
                            </p>
                            <p className="text-sm text-gray-400">꾸준히 하고 있어요!</p>
                        </div>
                    </div>
                </div>
            </div>

            {selectedImage && (
                <PhotoModal
                    src={selectedImage.src}
                    date={selectedImage.date}
                    studentName={selectedImage.studentName}
                    logId={selectedImage.id}
                    onClose={() => setSelectedImage(null)}
                    onImagesDeleted={() => {
                        setLogs(prev => prev.map(l => l.id === selectedImage.id ? { ...l, image_url: 'deleted' } : l));
                        setSelectedImage(prev => prev ? { ...prev, src: 'deleted' } : null);
                    }}
                />
            )}
        </main>
    );
}

"use client"; // Next.js에서 브라우저 화면(결제창)을 그리려면 꼭 맨 위에 써야 해!

import { useEffect, useRef, useState } from "react";
import { loadPaymentWidget, PaymentWidgetInstance } from "@tosspayments/payment-widget-sdk";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function PremiumPage() {
    // 문서에 있던 테스트 키 그대로 넣었어!
    const clientKey = "test_gck_docs_Ovk5rk1EwkEbP0W43n07xlzm";
    const customerKey = "ANONYMOUS"; // 로그인 안 한 익명 유저용

    const router = useRouter();

    // 결제 위젯을 기억해둘 빈 공간
    const paymentWidgetRef = useRef<PaymentWidgetInstance | null>(null);

    useEffect(() => {
        const fetchPaymentWidget = async () => {
            // 1. 토스 결제위젯 불러오기
            const paymentWidget = await loadPaymentWidget(clientKey, customerKey);

            // 2. 결제창 화면에 그리기 (1000원)
            paymentWidget.renderPaymentMethods(
                "#payment-method",
                { value: 1000 },
                { variantKey: "DEFAULT" }
            );

            // 3. 이용약관 화면에 그리기
            paymentWidget.renderAgreement("#agreement", { variantKey: "AGREEMENT" });

            paymentWidgetRef.current = paymentWidget;
        };

        fetchPaymentWidget();
    }, []);

    const handlePayment = async () => {
        const paymentWidget = paymentWidgetRef.current;
        if (!paymentWidget) return;

        try {
            // 결제 버튼을 누르면 실행되는 로직
            await paymentWidget.requestPayment({
                orderId: "PREMIUM_" + Date.now(),      // 겹치지 않는 주문번호
                orderName: "프리미엄 숙제 보기 권한",        // 상품명
                successUrl: window.location.origin + "/success", // 결제 성공 시 갈 페이지
                failUrl: window.location.origin + "/fail",       // 결제 실패 시 갈 페이지
            });
        } catch (error) {
            console.error("결제 중 에러 발생:", error);
        }
    };

    return (
        <>
            <div className="flex flex-col items-center justify-center min-h-screen p-10 bg-gray-50">
                <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md">
                    <h2 className="text-2xl font-bold text-center mb-6 text-gray-800">
                        숙제 전체 보기 프리미엄 (1,000원)
                    </h2>

                    {/* 결제수단과 약관이 들어갈 자리 */}
                    <div id="payment-method" className="w-full mb-4" />
                    <div id="agreement" className="w-full mb-6" />

                    {/* 결제 버튼 (Tailwind CSS 적용) */}
                    <button
                        onClick={handlePayment}
                        className="w-full py-4 bg-blue-500 hover:bg-blue-600 text-white font-bold rounded-xl transition-colors text-lg mb-4"
                    >
                        1,000원 결제하기
                    </button>

                    <Link
                        href="/"
                        className="block text-center text-sm text-gray-500 hover:text-gray-800 transition-colors mt-2"
                    >
                        홈으로 돌아가기
                    </Link>
                </div>
            </div>
        </>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "@/lib/supabase";

export default function SuccessPage() {
    const router = useRouter();
    const [groupName, setGroupName] = useState("");
    const [groupPassword, setGroupPassword] = useState("");
    const [isCreating, setIsCreating] = useState(false);
    const [errorMsg, setErrorMsg] = useState("");

    // Generate a secure random ID for the group if we don't rely solely on DB auto-increment
    const handleCreateGroup = async () => {
        if (!groupName.trim() || !groupPassword.trim()) {
            setErrorMsg("공부방 이름과 비밀번호를 모두 입력해주세요.");
            return;
        }

        setIsCreating(true);
        setErrorMsg("");

        try {
            // Insert new group into Supabase
            const { data, error } = await supabase
                .from('premium_groups')
                .insert([
                    {
                        name: groupName.trim(),
                        password: groupPassword.trim(),
                        max_members: 200 // Default as requested
                    }
                ])
                .select()
                .single();

            if (error) throw error;

            // Success! Save to local storage
            localStorage.setItem('premium_group_id', data.id);
            localStorage.setItem('premium_group_name', data.name);

            // Redirect to role selection as the Teacher
            router.push('/group/role-select');

        } catch (err) {
            console.error("Group creation error:", err);
            setErrorMsg("그룹 생성 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.");
        } finally {
            setIsCreating(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 p-6">
            <div className="bg-white p-8 md:p-10 rounded-3xl shadow-xl flex flex-col max-w-md w-full animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="text-center mb-6">
                    <div className="text-5xl mb-4">🎉</div>
                    <h1 className="text-2xl font-bold text-gray-900 mb-2">
                        결제가 완료되었습니다!
                    </h1>
                    <p className="text-gray-500 text-sm">
                        이제 선생님만의 전용 프리미엄 공부방을 बना볼까요?<br />
                        최대 200명의 학생이 참여할 수 있습니다.
                    </p>
                </div>

                <div className="space-y-4 mb-8">
                    <div>
                        <label className="block text-sm font-bold text-gray-700 mb-1 ml-1">공부방 이름</label>
                        <input
                            type="text"
                            value={groupName}
                            onChange={(e) => setGroupName(e.target.value)}
                            placeholder="예: 호랑이반 수학 특훈"
                            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-toss-blue focus:ring-2 focus:ring-blue-100 outline-none transition-all"
                            disabled={isCreating}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-gray-700 mb-1 ml-1">입장 비밀번호</label>
                        <input
                            type="password"
                            value={groupPassword}
                            onChange={(e) => setGroupPassword(e.target.value)}
                            placeholder="학생들이 입장할 때 쓸 비밀번호"
                            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-toss-blue focus:ring-2 focus:ring-blue-100 outline-none transition-all font-medium placeholder:font-normal"
                            disabled={isCreating}
                        />
                        <p className="text-xs text-gray-400 mt-2 ml-1">
                            * 이 비밀번호를 학생들에게 알려주시면, 앱 메인에서 &apos;단체 코드로 입장하기&apos;를 통해 접속할 수 있습니다.
                        </p>
                    </div>

                    {errorMsg && (
                        <p className="text-red-500 text-sm text-center font-bold">
                            {errorMsg}
                        </p>
                    )}
                </div>

                <button
                    onClick={handleCreateGroup}
                    disabled={isCreating || !groupName.trim() || !groupPassword.trim()}
                    className={`
                        w-full py-4 rounded-xl text-lg font-bold shadow-lg transition-all flex justify-center items-center
                        ${isCreating || !groupName.trim() || !groupPassword.trim()
                            ? 'bg-gray-200 text-gray-400 cursor-not-allowed shadow-none'
                            : 'bg-toss-blue hover:bg-blue-600 text-white shadow-blue-500/30 active:scale-95'
                        }
                    `}
                >
                    {isCreating ? (
                        <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    ) : (
                        "공부방 생성 및 시작하기 🚀"
                    )}
                </button>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { TeacherFeedback } from './TeacherFeedback';

interface PremiumHomeworkModalProps {
    homework: {
        id: string;
        student_name: string;
        image_urls: string[];
        study_date: string;
        created_at: string;
        description?: string;
    } | null;
    onClose: () => void;
    onUpdate?: () => void; // 부모 컴포넌트의 데이터 리프레시 용도
}

export function PremiumHomeworkModal({ homework, onClose, onUpdate }: PremiumHomeworkModalProps) {
    const [currentImageIdx, setCurrentImageIdx] = useState(0);

    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        window.addEventListener('keydown', handleEsc);
        return () => window.removeEventListener('keydown', handleEsc);
    }, [onClose]);

    if (!homework) return null;

    return (
        <div
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 md:p-10 animate-in fade-in duration-200"
            onClick={onClose}
        >
            <div
                className="bg-white rounded-3xl max-w-4xl w-full max-h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                {/* Modal Header */}
                <div className="flex items-center justify-between p-6 border-b border-gray-100 bg-white shrink-0">
                    <div>
                        <h2 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            {homework.student_name}의 숙제 📝
                        </h2>
                        <p className="text-sm text-gray-500 mt-1">
                            제출 시간: {new Date(homework.created_at).toLocaleString()}
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        className="w-10 h-10 bg-gray-100 hover:bg-gray-200 rounded-full flex items-center justify-center text-gray-500 transition-colors"
                    >
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                    </button>
                </div>

                {/* Modal Body */}
                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                        {/* Left: Image Gallery */}
                        <div className="space-y-4">
                            {homework.image_urls && homework.image_urls.length > 0 ? (
                                <>
                                    <div className="relative aspect-square bg-gray-50 rounded-2xl overflow-hidden border border-gray-100 flex items-center justify-center">
                                        <img
                                            src={homework.image_urls[currentImageIdx]}
                                            alt="Homework"
                                            className="object-contain w-full h-full"
                                        />

                                        {homework.image_urls.length > 1 && (
                                            <>
                                                <button
                                                    onClick={() => setCurrentImageIdx((prev) => (prev > 0 ? prev - 1 : homework.image_urls.length - 1))}
                                                    className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 bg-black/30 hover:bg-black/50 text-white rounded-full flex items-center justify-center transition-colors"
                                                >
                                                    &larr;
                                                </button>
                                                <button
                                                    onClick={() => setCurrentImageIdx((prev) => (prev < homework.image_urls.length - 1 ? prev + 1 : 0))}
                                                    className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 bg-black/30 hover:bg-black/50 text-white rounded-full flex items-center justify-center transition-colors"
                                                >
                                                    &rarr;
                                                </button>
                                            </>
                                        )}
                                    </div>

                                    {/* Thumbnails */}
                                    {homework.image_urls.length > 1 && (
                                        <div className="flex gap-2 overflow-x-auto pb-2 custom-scrollbar">
                                            {homework.image_urls.map((url, idx) => (
                                                <button
                                                    key={idx}
                                                    onClick={() => setCurrentImageIdx(idx)}
                                                    className={`
                                                        w-14 h-14 rounded-lg overflow-hidden border-2 transition-all shrink-0
                                                        ${currentImageIdx === idx ? 'border-toss-blue scale-105 shadow-md' : 'border-transparent opacity-60'}
                                                    `}
                                                >
                                                    <img src={url} alt="thumb" className="w-full h-full object-cover" />
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </>
                            ) : (
                                <div className="aspect-square bg-gray-50 rounded-2xl border border-dashed border-gray-300 flex flex-col items-center justify-center p-6 text-center animate-in fade-in">
                                    <span className="text-4xl mb-3">💣</span>
                                    <h4 className="font-bold text-gray-700 mb-1">사진이 삭제되었습니다</h4>
                                    <p className="text-sm text-gray-400">데이터 비용 절감을 위해<br />검사 완료된 사진은 자동 파기됩니다.</p>
                                </div>
                            )}
                        </div>

                        {/* Right: Info & Feedback */}
                        <div className="space-y-6">
                            <div className="bg-gray-50 p-5 rounded-2xl border border-gray-100 shadow-inner">
                                <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">학생 설명</h3>
                                <p className="text-gray-800 leading-relaxed font-medium">
                                    {homework.description || "등록된 설명이 없습니다."}
                                </p>
                            </div>

                            {/* Teacher Feedback Component */}
                            <TeacherFeedback
                                homeworkId={homework.id}
                                imageUrls={homework.image_urls}
                                onClose={onClose}
                                onImagesDeleted={() => {
                                    if (onUpdate) onUpdate();
                                }}
                            />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { PremiumHomeworkModal } from './PremiumHomeworkModal';
import { supabase } from '@/lib/supabase';
import { motion } from 'framer-motion';

interface Homework {
    id: string;
    student_name: string;
    image_urls: string[];
    study_date: string;
    created_at: string;
    description?: string;
    feedback_count?: number;
}

interface TeacherDashboardGridProps {
    homeworks: Homework[];
}

export function TeacherDashboardGrid({ homeworks }: TeacherDashboardGridProps) {
    const [selectedHw, setSelectedHw] = useState<Homework | null>(null);
    const [processedHws, setProcessedHws] = useState<Homework[]>([]);
    const [showUnreadOnly, setShowUnreadOnly] = useState(false);

    useEffect(() => {
        const fetchFeedbackCounts = async () => {
            // Get all homework IDs
            const hIds = homeworks.map(h => h.id);
            if (hIds.length === 0) {
                setProcessedHws([]);
                return;
            }

            // Fetch feedback for these homeworks
            const { data: feedbackData } = await supabase
                .from('premium_feedback')
                .select('homework_id')
                .in('homework_id', hIds);

            const newHws = homeworks.map(hw => ({
                ...hw,
                feedback_count: feedbackData?.filter(f => f.homework_id === hw.id).length || 0
            }));

            setProcessedHws(newHws);
        };

        fetchFeedbackCounts();
    }, [homeworks]);

    // Filter to get the latest homework per student (in case they submit multiple times today)
    const uniqueStudents = processedHws.reduce((acc, curr) => {
        if (!acc.some(h => h.student_name === curr.student_name)) {
            acc.push(curr);
        }
        return acc;
    }, [] as Homework[]);

    const displayedStudents = showUnreadOnly
        ? uniqueStudents.filter(hw => (hw.feedback_count || 0) === 0)
        : uniqueStudents;

    if (uniqueStudents.length === 0) {
        return (
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="flex flex-col items-center justify-center py-24 px-6 bg-white rounded-[2rem] border-2 border-dashed border-gray-200"
            >
                <div className="text-7xl mb-6 animate-bounce">
                    😴
                </div>
                <h3 className="text-2xl font-extrabold text-gray-900 mb-2">아직 빈둥빈둥..</h3>
                <p className="text-gray-500 font-medium text-lg text-center">
                    아직 숙제를 제출한 학생이 없어요.<br />
                    <span className="text-sm text-gray-400 mt-2 block">실시간으로 업데이트 대기 중... ⏳</span>
                </p>
            </motion.div>
        );
    }

    return (
        <div className="space-y-8">
            <div className="flex justify-end pr-2">
                <label className="flex items-center gap-3 cursor-pointer group bg-gray-50 px-4 py-2 rounded-full border border-gray-100 hover:bg-gray-100 transition-colors">
                    <span className="text-sm font-bold text-gray-700 select-none group-hover:text-toss-blue transition-colors">
                        ✅ 안 읽은 숙제만 보기
                    </span>
                    <div className="relative">
                        <input
                            type="checkbox"
                            checked={showUnreadOnly}
                            onChange={(e) => setShowUnreadOnly(e.target.checked)}
                            className="sr-only peer"
                        />
                        <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-toss-blue"></div>
                    </div>
                </label>
            </div>

            {displayedStudents.length === 0 ? (
                <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="flex flex-col items-center justify-center py-20 bg-blue-50/50 rounded-[2rem] border border-blue-100"
                >
                    <div className="text-7xl mb-6">
                        🎉
                    </div>
                    <h3 className="text-2xl font-extrabold text-toss-blue mb-2">짝짝짝! 모두 다 봤어요!</h3>
                    <p className="text-blue-600/70 font-medium text-lg text-center">
                        모든 학생의 숙제 검사를 완료했어요. 선생님 최고! 👍
                    </p>
                </motion.div>
            ) : (
                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6 w-full">
                    {displayedStudents.map((hw, index) => (
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.05 }}
                            key={hw.id}
                            className="relative bg-white border border-gray-100 rounded-[1.5rem] p-4 flex flex-col items-center shadow-sm hover:shadow-2xl hover:shadow-toss-blue/10 hover:-translate-y-2 transition-all duration-300 cursor-pointer group"
                            onClick={() => setSelectedHw(hw)}
                        >
                            {/* Status label / checkmark */}
                            <div className={`
                            absolute -top-3 -right-3 w-8 h-8 rounded-full flex items-center justify-center font-bold text-xs shadow-lg z-10 transition-transform duration-300 group-hover:scale-110 group-hover:rotate-12
                            ${(hw.feedback_count || 0) > 0
                                    ? 'bg-green-500 text-white ring-4 ring-green-50'
                                    : 'bg-orange-500 text-white ring-4 ring-orange-50 animate-pulse'}
                        `}>
                                {(hw.feedback_count || 0) > 0 ? '✓' : '!'}
                            </div>

                            {/* Thumbnail Container */}
                            <div className="w-full aspect-square rounded-2xl bg-gray-50 overflow-hidden mb-4 border border-gray-50 relative">
                                {hw.image_urls && hw.image_urls.length > 0 ? (
                                    <>
                                        <img
                                            src={hw.image_urls[0]}
                                            alt={`${hw.student_name}`}
                                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                                        />
                                        <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors duration-300" />
                                        {hw.image_urls.length > 1 && (
                                            <div className="absolute bottom-2 right-2 bg-black/70 text-white text-[10px] font-bold px-2 py-1 rounded-lg backdrop-blur-md shadow-sm">
                                                +{hw.image_urls.length - 1}장
                                            </div>
                                        )}
                                    </>
                                ) : (
                                    <div className="w-full h-full flex flex-col items-center justify-center text-gray-400 bg-gray-50/80">
                                        <span className="text-2xl mb-1">📝</span>
                                        <span className="text-xs font-bold">글만 작성함</span>
                                    </div>
                                )}
                            </div>

                            {/* Student Name & Meta */}
                            <div className="text-center w-full mt-auto">
                                <p className="font-extrabold text-gray-900 text-base mb-2 truncate group-hover:text-toss-blue transition-colors">{hw.student_name}</p>
                                <div className="flex items-center justify-center gap-2">
                                    <span className={`text-[11px] px-3 py-1 rounded-full font-bold shadow-sm transition-colors
                                    ${(hw.feedback_count || 0) > 0 ? 'bg-green-50 text-green-600 border border-green-100' : 'bg-orange-50 text-orange-600 border border-orange-100'}
                                `}>
                                        {(hw.feedback_count || 0) > 0 ? '검사완료' : '검사 대기중'}
                                    </span>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}

            {selectedHw && (
                <PremiumHomeworkModal
                    homework={selectedHw}
                    onClose={() => setSelectedHw(null)}
                />
            )}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import toast from 'react-hot-toast';

interface Feedback {
    id: string;
    content: string;
    reaction_type: string;
    created_at: string;
}

interface TeacherFeedbackProps {
    homeworkId: string;
    imageUrls?: string[];
    onClose?: () => void;
    onImagesDeleted?: () => void;
}

const REACTION_TYPES = [
    { type: 'clap', emoji: '👏', label: '참 잘했어요' },
    { type: 'heart', emoji: '❤️', label: '멋져요' },
    { type: 'star', emoji: '⭐', label: '최고예요' },
    { type: 'check', emoji: '✅', label: '확인완료 (사진 삭제)' },
];

export function TeacherFeedback({ homeworkId, imageUrls, onClose, onImagesDeleted }: TeacherFeedbackProps) {
    const [comment, setComment] = useState('');
    const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);
    const [loading, setLoading] = useState(false);
    const [selectedReaction, setSelectedReaction] = useState<string | null>(null);
    const [showStamp, setShowStamp] = useState(false);
    const [stampEmoji, setStampEmoji] = useState<string | null>(null);

    useEffect(() => {
        async function fetchFeedbacks() {
            const { data, error } = await supabase
                .from('premium_feedback')
                .select('*')
                .eq('homework_id', homeworkId)
                .order('created_at', { ascending: true });

            if (data) setFeedbacks(data);
        }

        fetchFeedbacks();

        // Subscribe to feedback changes
        const channel = supabase
            .channel(`feedback:${homeworkId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'premium_feedback',
                    filter: `homework_id=eq.${homeworkId}`,
                },
                () => fetchFeedbacks()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [homeworkId]);

    const handleSubmit = async (reactionType?: string) => {
        if (!comment.trim() && !reactionType) return;

        setLoading(true);

        const rType = reactionType || selectedReaction;

        try {
            // 1. 피드백 남기기
            const { error: feedbackError } = await supabase
                .from('premium_feedback')
                .insert({
                    homework_id: homeworkId,
                    content: comment.trim(),
                    reaction_type: rType,
                });

            if (feedbackError) throw feedbackError;

            // 2. [가성비 폭파 시스템] 선생님 확인 시 사진 즉시 지우기
            // 이미지가 남아있을 때만 실행
            if (imageUrls && imageUrls.length > 0) {
                // 스토리지 파일 삭제를 위해 경로(Key) 추출
                const filePaths = imageUrls.map(url => {
                    const parts = url.split('/premium-photos/');
                    return parts.length > 1 ? parts[1] : null;
                }).filter(Boolean) as string[];

                if (filePaths.length > 0) {
                    await supabase.storage.from('premium-photos').remove(filePaths);
                }

                // DB의 image_urls를 빈 배열로 밀어버리고 확인 마킹 추가
                await supabase
                    .from('premium_homeworks')
                    .update({
                        image_urls: [],
                        description: `[선생님 확인 완료 - 비용 절감을 위해 사진이 자동 폭파되었습니다 💣]\n\n학생: `
                    })
                    .eq('id', homeworkId);

                if (onImagesDeleted) onImagesDeleted();
            }

            setComment('');
            setSelectedReaction(null);

            const emoji = REACTION_TYPES.find(r => r.type === rType)?.emoji || '✅';
            setStampEmoji(emoji);
            setShowStamp(true);
            toast.success('피드백 전송 및 사진 자동 비우기 완료! 🗑️');

            setTimeout(() => {
                setShowStamp(false);
                if (onClose) onClose();
            }, 1500);

        } catch (error) {
            console.error('Feedback & Delete error:', error);
            toast.error('오류가 발생했습니다.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6 mt-6 border-t pt-6">
            <div className="space-y-4">
                <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider">선생님 칭찬 한마디</h3>

                {/* Reactions Grid */}
                <div className="grid grid-cols-4 gap-2">
                    {REACTION_TYPES.map((reaction) => (
                        <button
                            key={reaction.type}
                            onClick={() => handleSubmit(reaction.type)}
                            disabled={loading}
                            className={`
                                flex flex-col items-center justify-center p-3 rounded-2xl border transition-all
                                ${loading ? 'opacity-50 cursor-wait' : 'hover:scale-105 active:scale-95'}
                                ${feedbacks.some(f => f.reaction_type === reaction.type)
                                    ? 'bg-blue-50 border-toss-blue text-toss-blue'
                                    : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'}
                            `}
                        >
                            <span className="text-2xl mb-1">{reaction.emoji}</span>
                            <span className="text-[10px] font-bold">{reaction.label}</span>
                        </button>
                    ))}
                </div>

                {/* Comment Input */}
                <div className="relative group">
                    <textarea
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                        placeholder="이곳에 학생을 격려하는 메시지를 남겨주세요!"
                        className="w-full px-4 py-3 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-toss-blue outline-none transition-all resize-none min-h-[80px]"
                        disabled={loading}
                    />
                    <button
                        onClick={() => handleSubmit()}
                        disabled={loading || !comment.trim()}
                        className="absolute bottom-3 right-3 bg-toss-blue text-white px-4 py-1.5 rounded-full text-sm font-bold shadow-lg shadow-blue-500/20 hover:bg-blue-600 disabled:opacity-30 disabled:shadow-none transition-all"
                    >
                        등록
                    </button>
                </div>
            </div>

            {/* Feedback History */}
            {feedbacks.length > 0 && (
                <div className="space-y-3">
                    {feedbacks.map((f) => (
                        <div key={f.id} className="bg-blue-50/50 p-4 rounded-2xl border border-blue-50 flex items-start gap-3 animate-in fade-in slide-in-from-left-2 duration-300">
                            {f.reaction_type && (
                                <span className="text-xl bg-white w-10 h-10 rounded-full flex items-center justify-center shadow-sm shrink-0">
                                    {REACTION_TYPES.find(r => r.type === f.reaction_type)?.emoji}
                                </span>
                            )}
                            <div className="flex-1">
                                <p className="text-gray-800 text-sm leading-relaxed whitespace-pre-wrap">
                                    {f.content || REACTION_TYPES.find(r => r.type === f.reaction_type)?.label}
                                </p>
                                <p className="text-[10px] text-gray-400 mt-1">
                                    {new Date(f.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </p>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Stamp Animation Overlay */}
            {showStamp && (
                <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                    <div className="absolute inset-0 bg-white/20 backdrop-blur-[2px] animate-in fade-in duration-300"></div>
                    <div className="relative animate-in zoom-in spin-in-12 duration-500 flex flex-col items-center">
                        <span className="text-9xl drop-shadow-2xl translate-y-4">
                            {stampEmoji}
                        </span>
                        <div className="text-3xl font-black text-rose-500 -rotate-12 border-4 border-rose-500 p-2 rounded-xl bg-white/60 backdrop-blur-sm -translate-y-8 shadow-xl">
                            참 잘했어요!
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
